"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

const NAV_LINKS = [
  { label: "Product",      href: "/assessment" },
  { label: "How It Works", href: "/how-it-works.html" },
  { label: "Contact",      href: "/contact.html" },
];

export function Header() {
  const pathname = usePathname();

  return (
    <header
      className="fixed top-0 left-0 right-0 z-50 flex items-center justify-between px-14 py-5 bg-ink"
      style={{ borderBottom: "1px solid var(--border)" }}
    >
      <Link
        href="/"
        prefetch={false}
        style={{ fontFamily: "var(--font-display)" }}
        className="font-extrabold text-[1.1rem] tracking-[-0.03em] text-cream no-underline"
      >
        Repair<em className="not-italic text-lime">Sync</em>
      </Link>

      <nav className="flex items-center gap-10">
        {NAV_LINKS.map((link) => (
          <Link
            key={link.label}
            href={link.href}
            prefetch={false}
            className={`text-sm font-medium tracking-[0.01em] transition-colors no-underline ${
              pathname === link.href ? "text-cream" : "text-muted hover:text-cream"
            }`}
          >
            {link.label}
          </Link>
        ))}
      </nav>

      <Link
        href="/"
        prefetch={false}
        className="btn-accent no-underline"
      >
        Get Estimate
      </Link>
    </header>
  );
}

export function LayoutWrapper({ children }: { children: React.ReactNode }) {
  return (
    <div className="min-h-screen bg-ink text-cream">
      <Header />
      <main className="pt-24 px-8 pb-20">
        <div className="max-w-6xl mx-auto">
          {children}
        </div>
      </main>
    </div>
  );
}
